B.OZ=new A.c4("\xc7erez Politikas\u0131","Bu politika, Bilka Enneagram web sitesinin \xe7erez (cookie) kullan\u0131m\u0131na ili\u015fkin bilgileri i\xe7ermektedir. Sitemizi kullanmaya devam ederek bu politikay\u0131 kabul etmi\u015f say\u0131l\u0131rs\u0131n\u0131z.","Son g\xfcncelleme: Ocak 2025",!0)
B.P4=new A.c4("1. \xc7erez Nedir?","\xc7erezler, bir web sitesini ziyaret etti\u011finizde taray\u0131c\u0131n\u0131za kaydedilen k\xfc\xe7\xfck metin dosyalar\u0131d\u0131r. Bu dosyalar, sonraki ziyaretlerinizde sizi tan\u0131mam\u0131za ve deneyiminizi ki\u015fiselle\u015ftirmemize yard\u0131mc\u0131 olur.",null,!1)
B.OU=new A.c4("2. Kulland\u0131\u011f\u0131m\u0131z \xc7erez T\xfcrleri","Sitemizde a\u015fa\u011f\u0131daki \xe7erez t\xfcrleri kullan\u0131lmaktad\u0131r:\n\n\u2022 Zorunlu \xc7erezler: Sitenin temel i\u015flevlerini yerine getirebilmesi i\xe7in gereklidir. Bu \xe7erezler devre d\u0131\u015f\u0131 b\u0131rak\u0131lamaz.\n\n\u2022 \u0130\u015flevsel \xc7erezler: Dil tercihiniz gibi ayarlar\u0131n\u0131z\u0131 hat\u0131rlamak i\xe7in kullan\u0131l\u0131r.\n\n\u2022 Analitik \xc7erezler: Site kullan\u0131m\u0131n\u0131 anlamam\u0131za ve iyile\u015ftirmemize yard\u0131mc\u0131 olan istatistiksel veriler toplar. Kimli\u011finizi do\u011frudan a\xe7\u0131klamaz.\n\n\u2022 Oturum \xc7erezleri: Taray\u0131c\u0131 kapat\u0131ld\u0131\u011f\u0131nda otomatik olarak silinen ge\xe7ici \xe7erezlerdir.",null,!1)
B.OV=new A.c4("3. \xc7erezlerin Kullan\u0131m Amac\u0131","\xc7erezleri \u015fu ama\xe7larla kullan\u0131yoruz:\n\n\u2022 Oturum g\xfcvenli\u011fini sa\u011flamak\n\u2022 Test s\xfcrecinde ilerlemenizi ge\xe7ici olarak kaydetmek\n\u2022 Sitenin performans\u0131n\u0131 \xf6l\xe7mek ve iyile\u015ftirmek\n\u2022 Kullan\u0131c\u0131 deneyimini ki\u015fiselle\u015ftirmek",null,!1)
B.Pb=new A.c4("4. \xc7erez Y\xf6netimi","Taray\u0131c\u0131 ayarlar\u0131n\u0131zdan \xe7erezleri y\xf6netebilirsiniz:\n\n\u2022 T\xfcm \xe7erezleri engelleyebilirsiniz (bu durumda baz\u0131 site \xf6zellikleri \xe7al\u0131\u015fmayabilir)\n\u2022 Mevcut \xe7erezleri silebilirsiniz\n\u2022 Belirli sitelerden gelen \xe7erezleri kabul edebilir veya reddedebilirsiniz\n\nPop\xfcler taray\u0131c\u0131larda \xe7erez ayarlar\u0131: Chrome \u2192 Ayarlar \u2192 Gizlilik; Firefox \u2192 Tercihler \u2192 Gizlilik; Safari \u2192 Tercihler \u2192 Gizlilik.",null,!1)
B.Pc=new A.c4("5. \xdc\xe7\xfcnc\xfc Taraf \xc7erezleri","Sitemiz, analitik ama\xe7larla s\u0131n\u0131rl\u0131 \xfc\xe7\xfcnc\xfc taraf hizmetleri kullanabilir. Bu hizmetler kendi gizlilik politikalar\u0131 kapsam\u0131nda \xe7erez olu\u015fturabilir. S\xf6z konusu \xe7erezler \xfczerinde do\u011frudan kontrol\xfcm\xfcz bulunmamaktad\u0131r.",null,!1)
B.P0=new A.c4("6. Politika G\xfcncellemeleri","\xc7erez politikam\u0131z zaman zaman g\xfcncellenebilir. De\u011fi\u015fiklikler bu sayfada yay\u0131mlanarak y\xfcr\xfcrl\xfc\u011fe girer. D\xfczenli olarak kontrol etmenizi \xf6neririz.",null,!1)
B.Ph=new A.c4("7. \u0130leti\u015fim","\xc7erez politikam\u0131zla ilgili sorular\u0131n\u0131z i\xe7in:\n\nBilka Enneagram\nE-posta: info@bilkaenneagram.com.tr\nTelefon: +90 (555) 000 00 00",null,!1)
B.XW=s([B.OZ,B.P4,B.OU,B.OV,B.Pb,B.Pc,B.P0,B.Ph],t.J8)
B.OP=new A.pQ(B.XW,null)
B.Po=new A.c4("KVKK Ayd\u0131nlatma Metni","6698 say\u0131l\u0131 Ki\u015fisel Verilerin Korunmas\u0131 Kanunu'nun (KVKK) 10. maddesi uyar\u0131nca veri sorumlusu s\u0131fat\u0131yla haz\u0131rlanan bu ayd\u0131nlatma metni; Bilka Enneagram web sitesini ve test hizmetini kullanan ki\u015filere, ki\u015fisel verilerinin nas\u0131l topland\u0131\u011f\u0131, i\u015flendi\u011fi ve korundu\u011fu hakk\u0131nda bilgi vermek amac\u0131yla d\xfczenlenmi\u015ftir.","Son g\xfcncelleme: Ocak 2025",!0)
B.OY=new A.c4("1. Veri Sorumlusu","Veri Sorumlusu: Bilka Enneagram\nE-posta: info@bilkaenneagram.com.tr\nTelefon: +90 (555) 000 00 00\n\nKi\u015fisel verileriniz, yukar\u0131da belirtilen veri sorumlusu taraf\u0131ndan KVKK kapsam\u0131nda i\u015flenmektedir.",null,!1)
B.OT=new A.c4("2. \u0130\u015flenen Ki\u015fisel Veriler","Hizmetlerimiz arac\u0131l\u0131\u011f\u0131yla a\u015fa\u011f\u0131daki kategorilerdeki ki\u015fisel verileriniz toplanmakta ve i\u015flenmektedir:\n\n\u2022 Kimlik Verileri: Ad, soyad, do\u011fum tarihi\n\u2022 \u0130leti\u015fim Verileri: E-posta adresi, telefon numaras\u0131\n\u2022 Test ve Analiz Verileri: Enneagram testi cevaplar\u0131, ki\u015filik tipi sonu\xe7lar\u0131, miza\xe7 analizi raporu\n\u2022 \u0130\u015flem G\xfcvenli\u011fi Verileri: IP adresi, oturum bilgisi, taray\u0131c\u0131 t\xfcr\xfc\n\u2022 Onay ve \u0130zin Kay\u0131tlar\u0131: Gizlilik politikas\u0131 ve KVKK onay tarihleri",null,!1)
B.OW=new A.c4("3. Ki\u015fisel Verilerin \u0130\u015flenme Ama\xe7lar\u0131","Toplanan ki\u015fisel verileriniz a\u015fa\u011f\u0131daki ama\xe7lar do\u011frultusunda i\u015flenmektedir:\n\n\u2022 Enneagram testinin y\xfcr\xfct\xfclmesi ve ki\u015filik analizi sonu\xe7lar\u0131n\u0131n hesaplanmas\u0131\n\u2022 Test raporunun e-posta yoluyla iletilmesi\n\u2022 Miza\xe7 dan\u0131\u015fmanl\u0131\u011f\u0131 ve bireysel seans hizmetlerinin sunulmas\u0131\n\u2022 \u0130leti\u015fim taleplerine yan\u0131t verilmesi\n\u2022 Hizmet kalitesinin de\u011ferlendirilmesi ve iyile\u015ftirilmesi\n\u2022 Yasal y\xfck\xfcml\xfcl\xfcklerin yerine getirilmesi ve yetkili kurum taleplerine kar\u015f\u0131l\u0131k verilmesi",null,!1)
B.Pk=new A.c4("4. Hukuki \u0130\u015fleme Dayana\u011f\u0131","Ki\u015fisel verileriniz KVKK'n\u0131n 5. ve 6. maddeleri kapsam\u0131nda \u015fu hukuki dayanaklar \xe7er\xe7evesinde i\u015flenmektedir:\n\n\u2022 A\xe7\u0131k R\u0131za (m. 5/1): Test ve ki\u015filik analizi verilerinin i\u015flenmesi i\xe7in\n\u2022 S\xf6zle\u015fmenin Kurulmas\u0131 ve \u0130fas\u0131 (m. 5/2-c): Hizmet ili\u015fkisinin yerine getirilmesi i\xe7in\n\u2022 Me\u015fru Menfaat (m. 5/2-f): Hizmet kalitesinin geli\u015ftirilmesine y\xf6nelik istatistiksel analizler i\xe7in\n\u2022 Hukuki Y\xfck\xfcml\xfcl\xfck (m. 5/2-\xe7): Yasal saklama ve raporlama y\xfck\xfcml\xfcl\xfckleri i\xe7in",null,!1)
B.Pn=new A.c4("5. Ki\u015fisel Verilerin Aktar\u0131lmas\u0131","Ki\u015fisel verileriniz, a\u015fa\u011f\u0131daki durumlar d\u0131\u015f\u0131nda \xfc\xe7\xfcnc\xfc taraflarla payla\u015f\u0131lmaz:\n\n\u2022 Yasal zorunluluk kapsam\u0131nda yetkili kamu kurum ve kurulu\u015flar\u0131na\n\u2022 Hizmetin teknik altyap\u0131s\u0131n\u0131 sa\u011flayan ve KVKK uyumlu gizlilik s\xf6zle\u015fmesi imzalam\u0131\u015f tedarik\xe7ilere, yaln\u0131zca hizmetin ifas\u0131 i\xe7in zorunlu olan \xf6l\xe7\xfcde\n\nKi\u015fisel verileriniz kural olarak yurt d\u0131\u015f\u0131na aktar\u0131lmamaktad\u0131r. Zorunlu olmas\u0131 halinde yaln\u0131zca yeterli koruma seviyesine sahip veya taahh\xfctname imzalam\u0131\u015f \xfclkelerle aktar\u0131m yap\u0131l\u0131r.",null,!1)
B.P1=new A.c4("6. Ki\u015fisel Verilerin Saklanma S\xfcresi","Ki\u015fisel verileriniz, hizmet ili\u015fkisinin sona ermesinin ard\u0131ndan ilgili mevzuatta \xf6ng\xf6r\xfclen s\xfcreler ve Bilka Enneagram'\u0131n me\u015fru menfaatleri do\u011frultusunda en fazla 3 (\xfc\xe7) y\u0131l s\xfcreyle muhafaza edilir. Bu s\xfcrenin dolmas\u0131n\u0131n ard\u0131ndan verileriniz; g\xfcvenli imha, silme veya anonimle\u015ftirme y\xf6ntemlerinden biri ile kal\u0131c\u0131 olarak ortadan kald\u0131r\u0131l\u0131r.",null,!1)
B.P7=new A.c4("7. KVKK'dan Do\u011fan Haklar\u0131n\u0131z","KVKK'n\u0131n 11. maddesi uyar\u0131nca veri sahibi s\u0131fat\u0131yla a\u015fa\u011f\u0131daki haklara sahipsiniz:\n\n\u2022 Ki\u015fisel verilerinizin i\u015flenip i\u015flenmedi\u011fini \xf6\u011frenme\n\u2022 \u0130\u015flenmi\u015fse buna ili\u015fkin bilgi talep etme\n\u2022 \u0130\u015flenme amac\u0131n\u0131 ve bu amaca uygun kullan\u0131l\u0131p kullan\u0131lmad\u0131\u011f\u0131n\u0131 \xf6\u011frenme\n\u2022 Yurt i\xe7inde veya yurt d\u0131\u015f\u0131nda aktar\u0131ld\u0131\u011f\u0131 \xfc\xe7\xfcnc\xfc ki\u015fileri bilme\n\u2022 Eksik veya yanl\u0131\u015f i\u015flenen verilerin d\xfczeltilmesini isteme\n\u2022 Amac\u0131n ortadan kalkmas\u0131 halinde silinmesini veya yok edilmesini talep etme\n\u2022 D\xfczeltme ve silme i\u015flemlerinin, aktar\u0131lan taraflara bildirilmesini isteme\n\u2022 Otomatik sistemler arac\u0131l\u0131\u011f\u0131yla analiz sonucunda aleyhinize do\u011fan karar\u0131n itiraz\u0131n\u0131 yapma\n\u2022 Kanuna ayk\u0131r\u0131 i\u015fleme nedeniyle u\u011fran\u0131lan zarar\u0131n tazminini talep etme",null,!1)
B.OX=new A.c4("8. Ba\u015fvuru Y\xf6ntemi","Yukar\u0131da say\u0131lan haklar\u0131n\u0131z\u0131 kullanmak i\xe7in kimli\u011finizi do\u011frulay\u0131c\u0131 belgelerle birlikte a\u015fa\u011f\u0131daki kanallar arac\u0131l\u0131\u011f\u0131yla Bilka Enneagram'a ba\u015fvurabilirsiniz:\n\nBilka Enneagram\nE-posta: info@bilkaenneagram.com.tr\nTelefon: +90 (555) 000 00 00\n\nBa\u015fvurunuz, KVKK'n\u0131n 13. maddesi gere\u011fince en ge\xe7 30 (otuz) g\xfcn i\xe7inde \xfccretsiz olarak yan\u0131tlanacakt\u0131r. Talebin ayr\u0131ca bir maliyet gerektirmesi durumunda Ki\u015fisel Verileri Koruma Kurulu taraf\u0131ndan belirlenen tarifeye g\xf6re \xfccret al\u0131nabilir.",null,!1)
B.WO=s([B.Po,B.OY,B.OT,B.OW,B.Pk,B.Pn,B.P1,B.P7,B.OX],t.J8)
B.OQ=new A.pQ(B.WO,null)
B.Pf=new A.c4("Gizlilik Politikas\u0131","Bilka Enneagram olarak ki\u015fisel verilerinizin gizlili\u011fini \xf6nemsiyoruz. Bu politika, web sitemizi ziyaret etti\u011finizde veya test hizmetimizi kulland\u0131\u011f\u0131n\u0131zda toplanan, i\u015flenen ve korunan veriler hakk\u0131nda sizi bilgilendirmek amac\u0131yla haz\u0131rlanm\u0131\u015ft\u0131r.","Son g\xfcncelleme: Ocak 2025",!0)
B.P_=new A.c4("1. Toplanan Veriler","Hizmetlerimizi kullanman\u0131z s\u0131ras\u0131nda a\u015fa\u011f\u0131daki ki\u015fisel veriler toplanabilir:\n\n\u2022 Ad ve soyad\n\u2022 E-posta adresi\n\u2022 Telefon numaras\u0131\n\u2022 Do\u011fum tarihi\n\u2022 Enneagram testi cevaplar\u0131 ve sonu\xe7lar\u0131\n\u2022 \u0130leti\u015fim formu i\xe7erikleri\n\nBu veriler yaln\u0131zca sa\u011flanan hizmetin sunulmas\u0131 amac\u0131yla kullan\u0131l\u0131r.",null,!1)
B.P6=new A.c4("2. Veri \u0130\u015fleme Amac\u0131","Toplanan veriler \u015fu ama\xe7larla i\u015flenir:\n\n\u2022 Enneagram testinin de\u011ferlendirilmesi ve sonu\xe7lar\u0131n hesaplanmas\u0131\n\u2022 Miza\xe7 dan\u0131\u015fmanl\u0131\u011f\u0131 randevular\u0131n\u0131n d\xfczenlenmesi\n\u2022 \u0130leti\u015fim taleplerinize yan\u0131t verilmesi\n\u2022 Hizmet kalitesinin art\u0131r\u0131lmas\u0131\n\u2022 Yasal y\xfck\xfcml\xfcl\xfcklerin yerine getirilmesi",null,!1)
B.P8=new A.c4("3. Veri Payla\u015f\u0131m\u0131","Ki\u015fisel verileriniz, a\xe7\u0131k r\u0131zan\u0131z olmadan \xfc\xe7\xfcnc\xfc taraflarla payla\u015f\u0131lmaz. Yaln\u0131zca \u015fu durumlarda payla\u015f\u0131m yap\u0131labilir:\n\n\u2022 Yasal zorunluluk bulunmas\u0131 halinde yetkili kamu kurum ve kurulu\u015flar\u0131yla\n\u2022 Hizmetin sunulmas\u0131 i\xe7in zorunlu teknik altyap\u0131 sa\u011flay\u0131c\u0131lar\u0131yla (gizlilik s\xf6zle\u015fmesi kapsam\u0131nda)",null,!1)
B.Pi=new A.c4("4. Veri Saklama S\xfcresi","Verileriniz, hizmet ili\u015fkisinin sona ermesinden itibaren yasal saklama y\xfck\xfcml\xfcl\xfckleri do\u011frultusunda en fazla 3 y\u0131l s\xfcreyle saklan\u0131r. Bu s\xfcre sonunda verileriniz g\xfcvenli bi\xe7imde silinir veya anonimle\u015ftirilir.",null,!1)
B.Pa=new A.c4("5. G\xfcvenlik","Ki\u015fisel verilerinizin g\xfcvenli\u011fi i\xe7in end\xfcstri standard\u0131 teknik ve idari \xf6nlemler uygulanmaktad\u0131r. Veriler \u015fifreli ba\u011flant\u0131lar \xfczerinden iletilir ve g\xfcvenli sunucularda saklan\u0131r.",null,!1)
B.P2=new A.c4("6. Haklar\u0131n\u0131z (KVKK)","Ki\u015fisel Verilerin Korunmas\u0131 Kanunu kapsam\u0131nda a\u015fa\u011f\u0131daki haklara sahipsiniz:\n\n\u2022 Verilerinizin i\u015flenip i\u015flenmedi\u011fini \xf6\u011frenme\n\u2022 \u0130\u015flenmi\u015fse buna ili\u015fkin bilgi talep etme\n\u2022 Yanl\u0131\u015f verilerin d\xfczeltilmesini isteme\n\u2022 Ko\u015fullar olu\u015ftu\u011funda silinmesini talep etme\n\u2022 \u0130\u015flemeye itiraz etme\n\nBu haklar\u0131n\u0131z\u0131 kullanmak i\xe7in a\u015fa\u011f\u0131daki adrese ba\u015fvurabilirsiniz.",null,!1)
B.P3=new A.c4("7. \u0130leti\u015fim","Gizlilik politikam\u0131zla ilgili sorular\u0131n\u0131z i\xe7in:\n\nBilka Enneagram\nE-posta: info@bilkaenneagram.com.tr\nTelefon: +90 (555) 000 00 00",null,!1)
B.Tz=s([B.Pf,B.P_,B.P6,B.P8,B.Pi,B.Pa,B.P2,B.P3],t.J8)
B.OR=new A.pQ(B.Tz,null)
B.P9=new A.c4("Kullan\u0131m Ko\u015fullar\u0131","Bu web sitesini ve hizmetlerimizi kullanarak a\u015fa\u011f\u0131daki kullan\u0131m ko\u015fullar\u0131n\u0131 kabul etmi\u015f say\u0131l\u0131rs\u0131n\u0131z. L\xfctfen bu ko\u015fullar\u0131 dikkatlice okuyunuz. Ko\u015fullar\u0131 kabul etmiyorsan\u0131z sitemizi ve hizmetlerimizi kullanmay\u0131n\u0131z.","Son g\xfcncelleme: Ocak 2025",!0)
B.Pj=new A.c4("1. Hizmetin Tan\u0131m\u0131","Bilka Enneagram, akademik temelli Enneagram miza\xe7 analizi testi ve dan\u0131\u015fmanl\u0131k hizmetleri sunmaktad\u0131r. Sunulan test ve de\u011ferlendirmeler psikolojik te\u015fhis niteli\u011fi ta\u015f\u0131mamakta olup ki\u015fisel geli\u015fim ve \xf6z-fark\u0131ndal\u0131k amac\u0131yla tasarlanm\u0131\u015ft\u0131r.",null,!1)
B.Pl=new A.c4("2. Kullan\u0131m \u015eartlar\u0131","Hizmetlerimizi kullan\u0131rken a\u015fa\u011f\u0131daki kurallara uymay\u0131 kabul edersiniz:\n\n\u2022 Do\u011fru ve g\xfcncel ki\u015fisel bilgi sa\u011flamak\n\u2022 Hizmetleri yaln\u0131zca yasal ama\xe7larla kullanmak\n\u2022 Ba\u015fkalar\u0131n\u0131n haklar\u0131n\u0131 ihlal etmemek\n\u2022 Sistemi k\xf6t\xfcye kullanmaya y\xf6nelik giri\u015fimlerde bulunmamak\n\u2022 Test sonu\xe7lar\u0131n\u0131 izinsiz ticari ama\xe7larla kullanmamak",null,!1)
B.P5=new A.c4("3. Fikri M\xfclkiyet","Bu sitedeki t\xfcm i\xe7erikler (metin, grafik, logo, test sorular\u0131 ve metodolojisi) Bilka Enneagram'\u0131n fikri m\xfclkiyeti olup telif hakk\u0131 yasalar\u0131yla korunmaktad\u0131r. \u0130\xe7eriklerin izinsiz kopyalanmas\u0131, da\u011f\u0131t\u0131lmas\u0131 veya ticari ama\xe7larla kullan\u0131lmas\u0131 yasakt\u0131r.",null,!1)
B.Pg=new A.c4("4. Sorumluluk S\u0131n\u0131rlamas\u0131","Bilka Enneagram, sunulan test ve de\u011ferlendirmelerin do\u011frulu\u011funu en \xfcst d\xfczeyde tutmaya \xe7al\u0131\u015fmakla birlikte:\n\n\u2022 Test sonu\xe7lar\u0131 profesyonel psikolojik tan\u0131 yerine ge\xe7mez\n\u2022 Sonu\xe7lar\u0131n kullan\u0131m\u0131ndan do\u011fabilecek kararlar kullan\u0131c\u0131ya aittir\n\u2022 Teknik aksakl\u0131klar veya veri kay\u0131plar\u0131ndan do\u011fan zararlar i\xe7in sorumluluk kabul edilmez",null,!1)
B.Pm=new A.c4("5. Hizmet De\u011fi\u015fiklikleri","Bilka Enneagram, \xf6nceden haber vermeksizin hizmet kapsam\u0131n\u0131, fiyatland\u0131rmas\u0131n\u0131 veya ko\u015fullar\u0131n\u0131 de\u011fi\u015ftirme hakk\u0131n\u0131 sakl\u0131 tutar. De\u011fi\u015fiklikler bu sayfada yay\u0131mland\u0131\u011f\u0131 anda y\xfcr\xfcrl\xfc\u011fe girer.",null,!1)
B.Pe=new A.c4("6. Uygulanacak Hukuk","Bu kullan\u0131m ko\u015fullar\u0131 T\xfcrkiye Cumhuriyeti yasalar\u0131na tabidir. Do\u011fabilecek uyu\u015fmazl\u0131klarda T\xfcrk mahkemeleri yetkilidir.",null,!1)
B.Pd=new A.c4("7. \u0130leti\u015fim","Kullan\u0131m ko\u015fullar\u0131yla ilgili sorular\u0131n\u0131z i\xe7in:\n\nBilka Enneagram\nE-posta: info@bilkaenneagram.com.tr\nTelefon: +90 (555) 000 00 00",null,!1)
