B.a5k=new A.aG("Ke\u015ffetmeyi ve yeni \u015feyler deneyimlemeyi seven, mant\u0131\u011f\u0131yla hareket eden, duygulara tak\u0131lmayan, iyimser, merakl\u0131, d\u0131\u015fa d\xf6n\xfck, ne\u015feli, konu\u015fkan ve giri\u015fken bir yap\u0131ya sahibim.")
